'DECLARE
    -- Standard Variables
    l_blob        BLOB;
    l_clob        CLOB;
    l_dest_offset INTEGER := 1;
    l_src_offset  INTEGER := 1;
    l_lang_ctx    INTEGER := dbms_lob.default_lang_ctx;
    l_warning     INTEGER;
    
    -- Data Variables
    l_sku         VARCHAR2(100);
    l_asin        VARCHAR2(100);
    l_name        VARCHAR2(4000);
    l_img         VARCHAR2(4000);
    l_cond        VARCHAR2(100);
    l_dims        VARCHAR2(100);
    l_unit        VARCHAR2(50);
    l_pack        VARCHAR2(100);
    l_qty         NUMBER;
BEGIN
    -- 1. Get the binary body
    l_blob := :body;

    -- 2. Initialize a temporary CLOB (Text storage)
    DBMS_LOB.CREATETEMPORARY(l_clob, TRUE);

    -- 3. Convert Binary (BLOB) to Text (CLOB) - The Safety Bridge
    IF DBMS_LOB.GETLENGTH(l_blob) > 0 THEN
        DBMS_LOB.CONVERTTOCLOB(
            dest_lob     => l_clob,
            src_blob     => l_blob,
            amount       => DBMS_LOB.LOBMAXSIZE,
  ' || '          dest_offset  => l_dest_offset,
            src_offset   => l_src_offset,
            blob_csid    => nls_charset_id(''UTF8''),
            lang_context => l_lang_ctx,
            warning      => l_warning
        );
    END IF;

    -- 4. Parse the CLOB (This is guaranteed to work)
    APEX_JSON.PARSE(l_clob);

    -- 5. Extract Values
    l_sku  := APEX_JSON.GET_VARCHAR2(''sku'');
    l_asin := APEX_JSON.GET_VARCHAR2(''asin'');
    l_name := UTL_I18N.UNESCAPE_REFERENCE(APEX_JSON.GET_VARCHAR2(''product_name''));
    l_img  := APEX_JSON.GET_VARCHAR2(''image_url'');
    l_cond := APEX_JSON.GET_VARCHAR2(''product_condition'');
    l_dims := APEX_JSON.GET_VARCHAR2(''dimensions'');
    l_unit := APEX_JSON.GET_VARCHAR2(''dimension_unit'');
    l_pack := APEX_JSON.GET_VARCHAR2(''packing_type'');
    l_qty  := APEX_JSON.GET_NUMBER(''total_available_qty'');

    -- 6. Merge Logic (Upsert)
    MERGE INTO ordg_products p
    USING (SELECT l_sku as sku FROM dual) src
    ON (p.sku =' || ' src.sku)
    WHEN MATCHED THEN
        UPDATE SET asin = l_asin, product_name = l_name, image_url = l_img,
                   product_condition = l_cond, dimensions = l_dims,
                   dimension_unit = l_unit, packing_type = l_pack,
                   total_available_qty = l_qty
    WHEN NOT MATCHED THEN
        INSERT (sku, asin, product_name, image_url, product_condition, 
                dimensions, dimension_unit, packing_type, total_available_qty)
        VALUES (l_sku, l_asin, l_name, l_img, l_cond, 
                l_dims, l_unit, l_pack, l_qty);

    -- 7. Response
    :status := 200;
    HTP.P(''{"message": "Success", "sku": "'' || l_sku || ''"}'');

    -- Cleanup
    DBMS_LOB.FREETEMPORARY(l_clob);

EXCEPTION WHEN OTHERS THEN
    :status := 400;
    HTP.P(''{"error": "'' || SQLERRM || ''"}'');
    IF l_clob IS NOT NULL THEN
        DBMS_LOB.FREETEMPORARY(l_clob);
    END IF;
END;');

