'DECLARE
    l_blob    BLOB;
    l_clob    CLOB;
    l_order   VARCHAR2(100);
    l_inbound VARCHAR2(100);
BEGIN
    -- Boilerplate to convert JSON body
    l_blob := :body;
    DBMS_LOB.CREATETEMPORARY(l_clob, TRUE);
    IF DBMS_LOB.GETLENGTH(l_blob) > 0 THEN
        DBMS_LOB.CONVERTTOCLOB(l_clob, l_blob, DBMS_LOB.LOBMAXSIZE, 1, 1, nls_charset_id(''UTF8''), dbms_lob.default_lang_ctx, dbms_lob.lobmaxsize);
    END IF;
    APEX_JSON.PARSE(l_clob);

    l_order   := APEX_JSON.GET_VARCHAR2(''order_no'');
    l_inbound := APEX_JSON.GET_VARCHAR2(''inbound_number'');

    -- Update the status
    UPDATE shipping_orders
    SET details_fetched = 1,
        inbound_number = l_inbound
    WHERE order_no = l_order;

    :status := 200;
    HTP.P(''{"message": "Order Marked Complete"}'');
    DBMS_LOB.FREETEMPORARY(l_clob);
END;');

