'DECLARE
    -- Blob/Clob Conversion Variables
    l_blob         BLOB;
    l_clob         CLOB;
    l_dest_offset INTEGER := 1;
    l_src_offset  INTEGER := 1;
    l_lang_ctx    INTEGER := dbms_lob.default_lang_ctx;
    l_warning     INTEGER;
    
    -- Data Variables
    l_order_no       VARCHAR2(100);
    l_order_name     VARCHAR2(255);
    l_status         VARCHAR2(50);
    l_date_created   VARCHAR2(50); 
    l_date_received  VARCHAR2(50);
    l_comment        VARCHAR2(4000);
BEGIN
    -- 1. Convert Binary to Text
    l_blob := :body;
    DBMS_LOB.CREATETEMPORARY(l_clob, TRUE);
    IF DBMS_LOB.GETLENGTH(l_blob) > 0 THEN
        DBMS_LOB.CONVERTTOCLOB(l_clob, l_blob, DBMS_LOB.LOBMAXSIZE, l_dest_offset, l_src_offset, nls_charset_id(''UTF8''), l_lang_ctx, l_warning);
    END IF;

    -- 2. Parse
    APEX_JSON.PARSE(l_clob);

    -- 3. Extract Data
    l_order_no      := APEX_JSON.GET_VARCHAR2(''order_no'');
    l_order_name    := APEX_JSON.GET_VARCHAR2(''order_' || 'name'');
    l_status        := APEX_JSON.GET_VARCHAR2(''status''); 
    l_date_created  := APEX_JSON.GET_VARCHAR2(''date_created'');
    l_date_received := APEX_JSON.GET_VARCHAR2(''date_received'');
    l_comment       := APEX_JSON.GET_VARCHAR2(''client_comment'');

    -- 4. Upsert into Inbound Shipments
    MERGE INTO inbound_shipments t
    USING (SELECT l_order_no as order_no FROM dual) src
    ON (t.order_no = src.order_no)
    
    WHEN MATCHED THEN
        UPDATE SET 
            status = l_status, 
            -- FIX: Only convert to date if it''s NOT ''pending''
            date_received = CASE 
                                WHEN LOWER(l_date_received) = ''pending'' THEN NULL 
                                ELSE TO_DATE(l_date_received, ''DD/MM/YYYY HH24:MI:SS'') 
                            END,
            client_comment = l_comment
            
    WHEN NOT MATCHED THEN
        INSERT (order_no, order_name, status, date_created, date_received, client_comment)
   ' || '     VALUES (
            l_order_no, 
            l_order_name, 
            l_status, 
            TO_DATE(l_date_created, ''DD/MM/YYYY HH24:MI:SS''), 
            -- FIX: Handle ''pending'' on initial insert too
            CASE 
                WHEN LOWER(l_date_received) = ''pending'' THEN NULL 
                ELSE TO_DATE(l_date_received, ''DD/MM/YYYY HH24:MI:SS'') 
            END, 
            l_comment
        );

    :status := 200;
    HTP.P(''{"message": "Shipment Synced", "id": "'' || l_order_no || ''"}'');
    DBMS_LOB.FREETEMPORARY(l_clob);

EXCEPTION WHEN OTHERS THEN
    :status := 400;
    HTP.P(''{"error": "'' || SQLERRM || ''"}'');
    IF l_clob IS NOT NULL THEN DBMS_LOB.FREETEMPORARY(l_clob); END IF;
END;');

