    -- Data Variables
    l_order_no       VARCHAR2(50);
    l_order_name     VARCHAR2(100);
    l_status         VARCHAR2(50);
    l_total_qty      NUMBER;
    l_total_sku      NUMBER;
    l_platform       VARCHAR2(50);
    l_comment        CLOB;
    l_date_created   VARCHAR2(50);
    l_date_shipped   VARCHAR2(50);

    -- Helper Procedure to Log safely (Saves even if main logic fails)
    PROCEDURE log_info(p_rec_id IN VARCHAR2, p_msg IN VARCHAR2, p_err IN CLOB DEFAULT NULL) IS
        PRAGMA AUTONOMOUS_TRANSACTION;
    BEGIN
        INSERT INTO api_debug_logs (api_name, record_id, message, error_details)
        VALUES (''sync_shipping_orders'', p_rec_id, p_msg, p_err);
        C' || 'OMMIT;
    END;

