        DBMS_LOB.CONVERTTOCLOB(l_clob, l_blob, l_amount, l_dest_offset, l_src_offset, nls_charset_id(''UTF8''), l_lang_ctx, l_warning);
    END IF;

    -- 2. Parse
    APEX_JSON.PARSE(l_clob);

    l_order_no     := APEX_JSON.GET_VARCHAR2(''order_no'');
    
    -- Log Start
    log_info(l_order_no, ''Started processing header'');

    l_order_name   := APEX_JSON.GET_VARCHAR2(''order_name'');
    l_status       := APEX_JSON.GET_VARCHAR2(''status'');
    l_total_qty    := APEX_JSON.GET_NUMBER(''total_quantity'');
    l_total_sku    := APEX_JSON.GET_NUMBER(''total_sku'');
    l_platform     := APEX_JSON.GET_VARCHAR2(''selling_platform'');
    l_comment      := APEX_JSON.GET_VARCHAR2(''client_comment'');
    l_date_created := APEX_JSON.GET_VARCHAR2(''date_created'');
    l_date_shipped := APEX_JSON.GET_VARCHAR2(''date_shipped'');
' || '
    -- 3. Upsert Logic
    MERGE INTO shipping_orders t
    USING (SELECT l_order_no as order_no FROM dual) src
    ON (t.order_no = src.order_no)
    
    WHEN MATCHED THEN
        UPDATE SET 
            selling_platform = l_platform,  -- <--- Updates the empty field
            status = l_status               -- Updates status while we are at it
            
    WHEN NOT MATCHED THEN
        INSERT (
            order_no, order_name, status, total_quantity, total_sku, 
            selling_platform, client_comment, date_created, date_shipped, 
            details_fetched
        )
        VALUES (
            l_order_no, l_order_name, l_status, l_total_qty, l_total_sku, 
            l_platform, l_comment, 
            TO_TIMESTAMP(l_date_created, ''DD/MM/YYYY HH24:MI:SS''), 
            TO_TIMESTAMP(l_date_shipped, ''DD/MM/YYYY HH24:MI:SS''),
            0
        );

    -- 4. Response & Log Success
    IF SQL%ROWCOUNT = 0 THEN
        log_info(l_order_no, ''Sk' || 'ipped: Order already exists'');
        :status := 200;
        HTP.P(''{"message": "Skipped", "id": "'' || l_order_no || ''"}'');
    ELSE
        log_info(l_order_no, ''Success: Created new order'');
        :status := 201; 
        HTP.P(''{"message": "Created", "id": "'' || l_order_no || ''"}'');
    END IF;
    
    DBMS_LOB.FREETEMPORARY(l_clob);

EXCEPTION WHEN OTHERS THEN
    -- Log Error
    log_info(l_order_no, ''CRITICAL FAILURE'', SQLERRM);
    
    :status := 400;
    HTP.P(''{"error": "'' || SQLERRM || ''"}'');
    IF l_clob IS NOT NULL THEN DBMS_LOB.FREETEMPORARY(l_clob); END IF;
END;');

